+    /// Get style for job status.
+    fn status_style(status: JobStatus, theme: &Theme) -> Style {
+        match status {
+            JobStatus::Completed => theme.success_style(),
+            JobStatus::Running => theme.info_style(),
+            JobStatus::Failed => theme.error_style(),
